prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model
  ?modelName
  ?originalId
  ?normalizedId
  (COUNT(DISTINCT ?choreo) AS ?choreoCount)
  (COUNT(DISTINCT ?start) AS ?startCount)
  (COUNT(DISTINCT ?task) AS ?taskCount)
WHERE {
  {
    ?model a bboExt:Model ;
           tai:normalizedId "2b18c5f00a5a46159c6cb6a3e2bc79e9" .
  }
  UNION
  {
    ?model a bboExt:Model ;
           tai:originalId "2b18c5f00a5a46159c6cb6a3e2bc79e9" .
  }

  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }

  ?model tai:belongsTo ?org .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?task a bboExt:ChoreographyTask ; tai:belongsTo ?choreo . }
}
GROUP BY ?model ?modelName ?originalId ?normalizedId
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  ?taskName
  ?taskId
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "sid_3406c2ea_744f_4829_b96a_36cd98fa7c13" ;
         tai:belongsTo ?org .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bbo:id ?taskId . }

  FILTER( !BOUND(?taskName) || FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Auftrag"))) )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?task
  ?taskName
  ?taskId
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "sid_3406c2ea_744f_4829_b96a_36cd98fa7c13" .
  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bbo:id ?taskId . }

  FILTER(CONTAINS(LCASE(COALESCE(STR(?taskName), "")), LCASE("Auftrag")))
}
LIMIT 25
